"""Baked-in reference data to save weight file slots.

This file contains base64-encoded reference embeddings and class mapping
so we can use all 3 weight file slots for ONNX models (2 YOLO + 1 classifier).
"""

import base64
import json
import io
import numpy as np

EMBEDDINGS_B64 = """"""

CLASS_MAPPING_B64 = """"""


def load_reference_embeddings() -> np.ndarray:
    """Decode and return reference embeddings array."""
    raw = base64.b64decode(EMBEDDINGS_B64)
    return np.load(io.BytesIO(raw))


def load_class_mapping() -> dict[int, int]:
    """Decode and return ImageFolder index -> category_id mapping."""
    raw = base64.b64decode(CLASS_MAPPING_B64).decode("utf-8")
    data = json.loads(raw)
    return {int(k): int(v) for k, v in data.items()}
